#include <stdio.h>
#include <ctype.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char s[N + 1];
        scanf("%s", s);
        int upper = 0, lower = 0;
        for (int i = 0; i < N; i++) {
            if (isupper(s[i])) upper++;
            else lower++;
        }
        if (upper <= K && lower <= K) printf("both\n");
        else if (upper <= K) printf("chef\n");
        else if (lower <= K) printf("brother\n");
        else printf("none\n");
    }
    return 0;
}

