code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            String s = sc.next();
            int upper = 0, lower = 0;
            for (char c : s.toCharArray()) {
                if (Character.isUpperCase(c)) upper++;
                else lower++;
            }
            if (upper <= K && lower <= K) System.out.println("both");
            else if (upper <= K) System.out.println("chef");
            else if (lower <= K) System.out.println("brother");
            else System.out.println("none");
        }
    }
}

