function nextInt() {
    return parseInt(lines[idx++]);
}

function nextString() {
    return lines[idx++];
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextString().split(' ').map(Number);
    let s = nextString();
    let upper = 0, lower = 0;
    for (let c of s) {
        if (c === c.toUpperCase()) upper++;
        else lower++;
    }
    if (upper <= K && lower <= K) console.log('both');
    else if (upper <= K) console.log('chef');
    else if (lower <= K) console.log('brother');
    else console.log('none');
}

